"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { getProfile, updateProfile } from "@/lib/api";

export default function AdminSettingsPage() {
  const queryClient = useQueryClient();
  const profileQuery = useQuery({
    queryKey: ["admin-profile"],
    queryFn: getProfile,
  });

  const updateMutation = useMutation({
    mutationFn: updateProfile,
    onSuccess: () => {
      toast.success("Profile updated successfully.");
      queryClient.invalidateQueries({ queryKey: ["admin-profile"] });
    },
  });

  function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const formData = new FormData(event.currentTarget);
    updateMutation.mutate(formData);
  }

  return (
    <Card className="max-w-3xl p-6">
      <h1 className="text-[32px] font-semibold leading-[120%] text-slate-900">Settings</h1>
      <p className="mt-2 text-base font-medium leading-[120%] text-slate-500">Keep admin account information current.</p>
      <form className="mt-6 grid gap-4 md:grid-cols-2" onSubmit={handleSubmit}>
        <Input name="name" defaultValue={profileQuery.data?.name || ""} placeholder="Full name" />
        <Input name="phone" defaultValue={profileQuery.data?.phone || ""} placeholder="Phone number" />
        <div className="md:col-span-2">
          <Input name="address" defaultValue={profileQuery.data?.address || ""} placeholder="Address" />
        </div>
        <div className="md:col-span-2">
          <Button type="submit" disabled={updateMutation.isPending}>
            {updateMutation.isPending ? "Saving..." : "Save profile"}
          </Button>
        </div>
      </form>
    </Card>
  );
}
